"use client";

import { type NavigationListProps, NavigationList as NavigationListRoot } from "./navigation-list";
import { NavigationListBadge } from "./navigation-list-badge";
import { NavigationListGroup, type NavigationListGroupProps } from "./navigation-list-group";
import { NavigationListItem, type NavigationListItemProps } from "./navigation-list-item";
import { NavigationListMeta, type NavigationListMetaProps } from "./navigation-list-meta";
import {
  NavigationListProgress,
  type NavigationListProgressProps,
} from "./navigation-list-progress";
import { NavigationListStatus, type NavigationListStatusProps } from "./navigation-list-status";
import {
  NavigationListSubtitle,
  type NavigationListSubtitleProps,
} from "./navigation-list-subtitle";
import { NavigationListTitle, type NavigationListTitleProps } from "./navigation-list-title";

const NavigationList = Object.assign(NavigationListRoot, {
  Item: NavigationListItem,
  Badge: NavigationListBadge,
  Title: NavigationListTitle,
  Status: NavigationListStatus,
  Meta: NavigationListMeta,
  Subtitle: NavigationListSubtitle,
  Progress: NavigationListProgress,
  Group: NavigationListGroup,
});

export { NavigationList, type NavigationListProps };
export type { NavigationListIndicator } from "./navigation-list-context";
export { NavigationListItem, type NavigationListItemProps };
export { NavigationListBadge };
export type { BadgeProps as NavigationListBadgeProps } from "../badge/badge";
export { NavigationListTitle, type NavigationListTitleProps };
export { NavigationListStatus, type NavigationListStatusProps };
export { NavigationListMeta, type NavigationListMetaProps };
export { NavigationListSubtitle, type NavigationListSubtitleProps };
export { NavigationListProgress, type NavigationListProgressProps };
export { NavigationListGroup, type NavigationListGroupProps };

"use client";

import {
  Children,
  type ComponentPropsWithRef,
  isValidElement,
  type KeyboardEvent,
  type ReactNode,
  useCallback,
  useId,
  useMemo,
  useRef,
} from "react";
import { getEncodedListboxItemId, type ListboxMetadataItem, useListbox } from "@/hooks/use-listbox";
import { composeRefs } from "@/lib/compose-refs";
import { cn } from "@/lib/utils";
import {
  type GroupHeaderRegistration,
  NavigationListContext,
  type NavigationListIndicator,
} from "./navigation-list-context";
import { NavigationListGroup } from "./navigation-list-group";
import { NavigationListItem } from "./navigation-list-item";

function collectNavigationListItems(children: ReactNode): ListboxMetadataItem[] {
  const items: ListboxMetadataItem[] = [];

  Children.forEach(children, (child) => {
    if (
      !isValidElement<{
        id?: string;
        disabled?: boolean;
        children?: ReactNode;
        variant?: string;
        headerId?: string;
        label?: string;
      }>(child)
    )
      return;

    if (child.type === NavigationListItem && typeof child.props.id === "string") {
      items.push({ id: child.props.id, disabled: child.props.disabled });
      return;
    }

    if (child.type === NavigationListGroup) {
      const variant = child.props.variant ?? "section";
      if (variant === "tree" && typeof child.props.headerId === "string") {
        items.push({ id: child.props.headerId });
      }
      if (variant === "section" && typeof child.props.label === "string") {
        const headerId = child.props.headerId ?? `__section_${child.props.label}`;
        items.push({ id: headerId });
      }
    }

    // Always collect items from groups regardless of expanded state.
    // Collapsed groups hide children from the DOM, so useNavigation's
    // DOM queries naturally exclude them from keyboard navigation.
    // The metadata list is only used for active-descendant resolution
    // and initial highlight — both safe with a superset.
    if (child.props.children) {
      items.push(...collectNavigationListItems(child.props.children));
    }
  });

  return items;
}

export interface NavigationListProps
  extends Omit<ComponentPropsWithRef<"div">, "children" | "onKeyDown" | "onSelect"> {
  selectedId?: string | null;
  defaultSelectedId?: string | null;
  highlighted?: string | null;
  defaultHighlighted?: string | null;
  onSelect?: (id: string) => void;
  onEnter?: (id: string, event: globalThis.KeyboardEvent) => void;
  onHighlightChange?: (id: string | null) => void;
  onNavigationBoundaryReached?: (
    direction: "previous" | "next",
    event: globalThis.KeyboardEvent,
    key: string,
  ) => void;
  indicator?: NavigationListIndicator;
  focused?: boolean;
  wrap?: boolean;
  autoFocus?: boolean;
  children: ReactNode;
  onKeyDown?: (event: KeyboardEvent) => void;
}

export function NavigationList({
  selectedId: controlledSelectedId,
  defaultSelectedId = null,
  highlighted: controlledHighlighted,
  defaultHighlighted = null,
  onSelect,
  onEnter,
  onHighlightChange,
  onNavigationBoundaryReached,
  indicator = "bar",
  focused = true,
  wrap = true,
  autoFocus = false,
  className,
  children,
  onKeyDown,
  "aria-label": ariaLabel,
  ref,
  ...rootProps
}: NavigationListProps) {
  const idPrefix = useId();
  const containerRef = useRef<HTMLDivElement | null>(null);
  const groupHeadersRef = useRef<Map<string, GroupHeaderRegistration>>(new Map());
  const items = useMemo(() => collectNavigationListItems(children), [children]);

  const handleGroupKeyDown = useCallback(
    (event: KeyboardEvent) => {
      onKeyDown?.(event);
      if (event.defaultPrevented) return;

      const key = event.key;
      if (key !== "ArrowLeft" && key !== "ArrowRight" && key !== "Enter" && key !== " ") return;

      const container = containerRef.current;
      if (!container) return;
      const activeId = container.getAttribute("aria-activedescendant");
      if (!activeId) return;

      const activeEl = container.ownerDocument.getElementById(activeId);
      if (!activeEl) return;
      const itemValue = activeEl.dataset.value;
      if (!itemValue) return;

      const registration = groupHeadersRef.current.get(itemValue);
      if (!registration) return;

      if (key === "ArrowRight") {
        if (!registration.expanded) {
          event.preventDefault();
          registration.toggle();
        }
        return;
      }

      if (key === "ArrowLeft") {
        if (registration.expanded) {
          event.preventDefault();
          registration.toggle();
        }
        return;
      }

      if (key === "Enter" || key === " ") {
        event.preventDefault();
        registration.toggle();
      }
    },
    [onKeyDown],
  );

  const { selectedId, highlighted, handleItemActivate, handleItemHighlight, getContainerProps } =
    useListbox({
      selectedId: controlledSelectedId,
      defaultSelectedId,
      highlighted: controlledHighlighted,
      defaultHighlighted,
      onSelect,
      onEnter,
      onHighlightChange,
      onNavigationBoundaryReached,
      wrap,
      idPrefix,
      autoFocus,
      onKeyDown: handleGroupKeyDown,
      typeahead: true,
      items,
      getItemId: getEncodedListboxItemId,
    });

  const registerGroupHeader = useCallback((id: string, registration: GroupHeaderRegistration) => {
    groupHeadersRef.current.set(id, registration);
  }, []);

  const unregisterGroupHeader = useCallback((id: string) => {
    groupHeadersRef.current.delete(id);
  }, []);

  const contextValue = useMemo(
    () => ({
      selectedId,
      highlighted,
      activate: handleItemActivate,
      highlight: handleItemHighlight,
      focusContainer: () => containerRef.current?.focus(),
      focused,
      idPrefix,
      indicator,
      registerGroupHeader,
      unregisterGroupHeader,
      groupHeaders: groupHeadersRef.current,
    }),
    [
      selectedId,
      highlighted,
      handleItemActivate,
      handleItemHighlight,
      focused,
      idPrefix,
      indicator,
      registerGroupHeader,
      unregisterGroupHeader,
    ],
  );

  return (
    <NavigationListContext value={contextValue}>
      {/* biome-ignore lint/a11y/useAriaPropsSupportedByRole: getContainerProps applies role="listbox" dynamically, which Biome cannot resolve; aria-label and aria-orientation are valid for the listbox role. */}
      <div
        {...rootProps}
        {...getContainerProps(composeRefs(containerRef, ref))}
        aria-label={ariaLabel}
        aria-orientation="vertical"
        className={cn("w-full outline-none", className)}
      >
        {children}
      </div>
    </NavigationListContext>
  );
}

"use client";

import { cva, type VariantProps } from "class-variance-authority";
import {
  Children,
  type ComponentPropsWithRef,
  type FocusEvent,
  isValidElement,
  type MouseEvent,
  type ReactNode,
  useMemo,
} from "react";
import { getEncodedListboxItemId } from "@/hooks/use-listbox";
import { cn } from "@/lib/utils";
import { useNavigationListContext } from "./navigation-list-context";
import {
  useNavigationListGroupContext,
  useNavigationListGroupPositionContext,
} from "./navigation-list-group-context";
import { NavigationListItemContext } from "./navigation-list-item-context";
import { NavigationListMeta } from "./navigation-list-meta";
import { NavigationListSubtitle } from "./navigation-list-subtitle";

const itemVariants = cva("flex cursor-pointer group", {
  variants: {
    active: {
      true: "bg-primary text-primary-foreground",
      false: "hover:bg-secondary border-b border-border/50",
    },
    disabled: {
      true: "opacity-50 cursor-not-allowed",
    },
    tree: {
      true: "",
      false: "",
    },
  },
  compoundVariants: [{ tree: true, active: false, className: "hover:bg-transparent border-b-0" }],
  defaultVariants: {
    active: false,
    disabled: false,
    tree: false,
  },
});

const contentVariants = cva("flex-1 grid grid-cols-[1fr_auto] auto-rows-auto gap-y-0.5", {
  variants: {
    density: {
      compact: "p-2",
      default: "p-3",
      comfortable: "p-4",
    },
  },
  defaultVariants: {
    density: "default",
  },
});

type Density = NonNullable<VariantProps<typeof contentVariants>["density"]>;

function hasDescriptionChild(
  children: ReactNode,
  childType: typeof NavigationListMeta | typeof NavigationListSubtitle,
): boolean {
  return Children.toArray(children).some((child) => {
    if (!isValidElement<{ children?: ReactNode }>(child)) return false;
    if (child.type === childType) return true;
    return hasDescriptionChild(child.props.children, childType);
  });
}

export interface NavigationListItemProps
  extends Omit<
    ComponentPropsWithRef<"div">,
    | "id"
    | "children"
    | "role"
    | "aria-selected"
    | "aria-disabled"
    | "aria-labelledby"
    | "aria-describedby"
  > {
  id: string;
  density?: Density;
  disabled?: boolean;
  children: ReactNode;
}

export function NavigationListItem({
  id,
  disabled = false,
  density = "default",
  children,
  className,
  ref,
  onClick,
  onMouseDown,
  onFocus,
  ...rootProps
}: NavigationListItemProps) {
  const {
    selectedId,
    highlighted,
    activate,
    highlight,
    focusContainer,
    focused,
    idPrefix,
    indicator,
  } = useNavigationListContext();
  const groupContext = useNavigationListGroupContext();
  const positionContext = useNavigationListGroupPositionContext();
  const isTree = groupContext.variant === "tree" && groupContext.depth > 0;
  const isSelected = !disabled && selectedId === id;
  const isHighlighted = !disabled && highlighted === id;
  const hasHighlight = highlighted !== null;
  const isActive = !disabled && focused && (hasHighlight ? isHighlighted : isSelected);
  const itemId = getEncodedListboxItemId(idPrefix, id);
  const labelId = `${itemId}-label`;
  const descId = `${itemId}-desc`;
  const describedBy =
    [
      hasDescriptionChild(children, NavigationListMeta) ? `${descId}-meta` : null,
      hasDescriptionChild(children, NavigationListSubtitle) ? `${descId}-sub` : null,
    ]
      .filter(Boolean)
      .join(" ") || undefined;

  const activeBarColorClass =
    indicator === "bar" ? "bg-primary-foreground/40" : "bg-primary-foreground";
  const indicatorColorClass = isActive
    ? activeBarColorClass
    : "bg-transparent group-hover:bg-muted";

  const handleClick = (event: MouseEvent<HTMLDivElement>) => {
    onClick?.(event);
    if (event.defaultPrevented || disabled) return;
    activate(id);
    focusContainer();
  };

  const handleMouseDown = (event: MouseEvent<HTMLDivElement>) => {
    onMouseDown?.(event);
    if (event.defaultPrevented) return;
    if (disabled) event.preventDefault();
  };

  const handleFocus = (event: FocusEvent<HTMLDivElement>) => {
    onFocus?.(event);
    if (!event.defaultPrevented && !disabled) highlight(id);
  };

  const itemContextValue = useMemo(() => ({ labelId, descId, isTree }), [labelId, descId, isTree]);

  return (
    <NavigationListItemContext value={itemContextValue}>
      {/* biome-ignore lint/a11y/useFocusableInteractive: WAI-ARIA listbox pattern — option stays non-focusable while the navigation list container holds focus and aria-activedescendant tracks the active option. */}
      {/* biome-ignore lint/a11y/useKeyWithClickEvents: Enter/Space activation is handled centrally by the navigation list container, not per option. */}
      <div
        {...rootProps}
        ref={ref}
        id={itemId}
        role="option"
        aria-labelledby={labelId}
        aria-describedby={describedBy}
        data-value={id}
        data-active={isActive || undefined}
        data-state={isSelected ? "selected" : "unselected"}
        aria-selected={isSelected}
        aria-disabled={disabled || undefined}
        onMouseDown={handleMouseDown}
        onClick={handleClick}
        onFocus={handleFocus}
        className={cn(
          itemVariants({ active: isActive, disabled, tree: isTree || undefined }),
          "focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-foreground",
          className,
        )}
      >
        {isTree && (
          <span
            aria-hidden="true"
            className="text-muted-foreground font-mono text-sm select-none shrink-0 self-center leading-none"
          >
            {groupContext.linePrefix}
            {positionContext?.isLast ? "└── " : "├── "}
          </span>
        )}
        {isTree ? (
          <div
            className={cn(
              "flex-1 flex items-center rounded-sm",
              isActive ? "bg-primary text-primary-foreground" : "hover:bg-secondary",
            )}
          >
            <div className="flex-1 grid grid-cols-[1fr_auto] auto-rows-auto gap-y-0.5 py-0.5 px-1">
              {children}
            </div>
          </div>
        ) : (
          <>
            <div
              data-indicator={indicator}
              className={cn(
                "shrink-0",
                (indicator === "bar" || indicator === "bar-thick") && [
                  indicator === "bar" ? "w-1" : "w-[4px]",
                  indicatorColorClass,
                ],
                (indicator === "arrow" || indicator === "bracket") && "w-1 bg-transparent",
              )}
            />
            <div className={contentVariants({ density })}>{children}</div>
          </>
        )}
      </div>
    </NavigationListItemContext>
  );
}

"use client";

import type { ReactNode } from "react";
import { cn } from "@/lib/utils";
import { useNavigationListContext } from "./navigation-list-context";
import { useNavigationListItemContext } from "./navigation-list-item-context";

const INDICATOR_GLYPHS = {
  bar: "\u258C",
  "bar-thick": "\u258C",
  arrow: ">",
  bracket: "[",
} as const;

export interface NavigationListTitleProps {
  children: ReactNode;
  className?: string;
}

export function NavigationListTitle({ children, className }: NavigationListTitleProps) {
  const { labelId, isTree } = useNavigationListItemContext();
  const { indicator } = useNavigationListContext();
  const glyph = INDICATOR_GLYPHS[indicator];

  return (
    <span
      id={labelId}
      className={cn(
        "col-start-1 row-start-1 font-bold flex items-center group-data-[active]:text-primary-foreground",
        className,
      )}
    >
      {!isTree && (
        <span aria-hidden="true" className="mr-2 opacity-30 group-data-[active]:opacity-100">
          {glyph}
        </span>
      )}
      {children}
      {!isTree && indicator === "bracket" && (
        <span aria-hidden="true" className="ml-2 opacity-30 group-data-[active]:opacity-100">
          {"]"}
        </span>
      )}
    </span>
  );
}

